/* CSS Simple & Detailed Buttons */
.btn-group-2 {
  display: flex;
  gap: 10px;
  width: 100%;
}

.btn-style-2 {
  flex: 1;
  height: auto;
  padding: 16px;
  border-radius: 8px;
  justify-content: center;
  align-items: center;
  gap: 4px;
  display: inline-flex;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  user-select: none;
  -webkit-user-select: none;
}

.btn-style-2.btn-secondary {
  background: #EEEFFA;
}

.btn-style-2.btn-secondary .btn-text {
  color: #585DCB;
}

.btn-style-2.btn-secondary:active {
  background-color: #e0e2f5;
  transform: scale(0.97);
}

.btn-style-2.btn-primary {
  background: #585DCB;
}

.btn-style-2.btn-primary .btn-text {
  color: white;
}

.btn-style-2.btn-primary:active {
  background-color: #4a4fb0;
  transform: scale(0.97);
}

.btn-style-2 .btn-text {
  text-align: center;
  font-size: 16px;
  font-family: 'Pretendard', -apple-system, sans-serif;
  font-weight: 500;
  line-height: 24px;
}
